mapper.select:
	SELECT IFNULL(SUM(pay_amount),0) envelopeAmount,COUNT(1) redEnvelopes FROM app_pay_amount_record
WHERE DATE_FORMAT(create_time,'%Y-%m-%d') = #{format}
AND type = 1

	SELECT IFNULL(SUM(pay_amount),0) plusEnevlopeAmount,COUNT(1) plusEnevlopeCount FROM app_pay_amount_record
WHERE DATE_FORMAT(create_time,'%Y-%m-%d') = #{format}
AND type = 2
